return $("Get Unprocessed Rows1").all().map(item => {
  return {
    json: {
      message_id: item.json.message_id
    }
  };
});

const sourceItems = $("Get Unprocessed Rows1").all();
const sourceRows = sourceItems.map(i => i.json);

const targetGroups = items.map(i => i.json);

if (!sourceRows.length || !targetGroups.length) return [];

const groups = {};

// Gom nhóm bài gốc:
// - có media_group_id => album
// - không có => single
for (const r of sourceRows) {
  const key = r.media_group_id ? `mg_${r.media_group_id}` : `single_${r.message_id}`;
  if (!groups[key]) groups[key] = [];
  groups[key].push(r);
}

// =========================
// HELPER: inject ref vào text/url
// =========================
function injectRef(text, refcode) {
  const s = String(text || '');
  const ref = String(refcode || '');

  if (!s || !ref) return s;

  // Chỉ cần có ref= ở đâu cũng thay
  if (!/ref=/i.test(s)) return s;

  // Chỉ replace ref= đầu tiên
  return s.replace(/ref=([^&#"\s>]*)/i, `ref=${ref}`);
}

// Trả về cả text mới + thông tin đoạn đã bị thay để còn chỉnh entity
function injectRefWithMeta(text, refcode) {
  const s = String(text || '');
  const ref = String(refcode || '');

  if (!s || !ref) {
    return {
      text: s,
      changed: false,
      start: -1,
      oldLength: 0,
      newLength: 0,
      delta: 0
    };
  }

  const match = s.match(/ref=([^&#"\s>]*)/i);
  if (!match || match.index == null) {
    return {
      text: s,
      changed: false,
      start: -1,
      oldLength: 0,
      newLength: 0,
      delta: 0
    };
  }

  const oldPart = match[0];
  const newPart = `ref=${ref}`;
  const start = match.index;

  const newText =
    s.slice(0, start) +
    newPart +
    s.slice(start + oldPart.length);

  return {
    text: newText,
    changed: oldPart !== newPart,
    start,
    oldLength: oldPart.length,
    newLength: newPart.length,
    delta: newPart.length - oldPart.length
  };
}

function parseEntities(input) {
  if (!input) return [];

  if (Array.isArray(input)) return input;

  if (typeof input === 'string') {
    const trimmed = input.trim();
    if (!trimmed) return [];

    try {
      const parsed = JSON.parse(trimmed);
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) {
      return [];
    }
  }

  return [];
}

// =========================
// HELPER: chỉnh offset/length entity khi text bị đổi độ dài
// =========================
function shiftEntitiesAfterReplace(inputEntities, replaceMeta) {
  const entities = parseEntities(inputEntities);
  if (!entities.length || !replaceMeta || !replaceMeta.changed || !replaceMeta.delta) {
    return entities;
  }

  const start = replaceMeta.start;
  const oldEnd = start + replaceMeta.oldLength;
  const delta = replaceMeta.delta;

  return entities.map(entity => {
    if (!entity || typeof entity.offset !== 'number' || typeof entity.length !== 'number') {
      return entity;
    }

    const eStart = entity.offset;
    const eEnd = entity.offset + entity.length;

    // entity nằm hoàn toàn trước đoạn replace
    if (eEnd <= start) {
      return { ...entity };
    }

    // entity nằm hoàn toàn sau đoạn replace
    if (eStart >= oldEnd) {
      return {
        ...entity,
        offset: entity.offset + delta
      };
    }

    // entity có overlap với đoạn replace
    // cần tăng length để vẫn phủ đúng phần text sau khi URL dài/ngắn đi
    return {
      ...entity,
      length: entity.length + delta
    };
  });
}

// Áp logic refcode vào entity nào có type = text_link
function injectRefToEntities(input, refcode) {
  const entities = parseEntities(input);
  if (!entities.length) return [];

  return entities.map(entity => {
    if (entity && entity.type === 'text_link' && entity.url) {
      return {
        ...entity,
        url: injectRef(entity.url, refcode)
      };
    }
    return { ...entity };
  });
}

// ưu tiên caption_entities, nếu không có thì fallback entities
function getBaseEntities(row) {
  const captionEntities = parseEntities(row.caption_entities);
  if (captionEntities.length) return captionEntities;

  const entities = parseEntities(row.entities);
  return entities.length ? entities : [];
}

// Nối CTA vào cuối nội dung
function appendCTA(content, cta) {
  const body = String(content || '').replace(/\n+$/g, '').trim();
  const tail = String(cta || '').replace(/^\n+/g, '').trim();

  if (!body && !tail) return '';
  if (!body) return tail;
  if (!tail) return body;

  return `${body}\n${tail}`;
}

// Lấy content + entities cuối cùng, đồng bộ offset/length sau khi chèn ref
function getFinalContentAndEntities(row, refcode, cta) {
  const rawCaption = String(row.caption || '');
  const baseEntities = getBaseEntities(row);

  // 1) sửa ref trong text hiển thị
  const injected = injectRefWithMeta(rawCaption, refcode);

  // 2) sửa offset/length entity theo độ lệch text
  let finalEntities = shiftEntitiesAfterReplace(baseEntities, injected);

  // 3) sửa riêng url của text_link entity
  finalEntities = injectRefToEntities(finalEntities, refcode);

  // 4) append CTA như logic cũ
  const finalContent = appendCTA(injected.text, cta);

  return {
    content: finalContent,
    entities: finalEntities
  };
}

const out = [];

for (const target of targetGroups) {
  const target_chat_id = String(target["ID GROUP"] || '').trim();
  const refcode = String(target["REFCODE"] || '').trim();
  const community_name = target["TÊN CỘNG ĐỒNG"] || '';
  const ctaRaw = target["CTA"] || '';
  const cta = injectRef(ctaRaw, refcode);

  if (!target_chat_id) continue;

  for (const [groupKey, arr] of Object.entries(groups)) {
    // sort để giữ đúng thứ tự album
    arr.sort((a, b) => Number(a.message_id || 0) - Number(b.message_id || 0));

    const rowIds = arr
      .map(r => r.id || r.rowId || r._id)
      .filter(Boolean);

    // =========================
    // CASE 1: SINGLE ITEM
    // =========================
    if (arr.length === 1) {
      const r = arr[0];
      const type = String(r.type || '').trim();
      const file_id = r.file_id || null;

      const { content: finalContent, entities: finalEntities } =
        getFinalContentAndEntities(r, refcode, cta);

      if (type === 'photo' && file_id) {
        out.push({
          json: {
            target_chat_id,
            refcode,
            community_name,
            group_key: `${groupKey}_${target_chat_id}`,
            source_group_key: groupKey,
            media_group_id: null,
            send_method: 'sendPhoto',
            payload: {
              chat_id: target_chat_id,
              photo: file_id,
              ...(finalContent ? { caption: finalContent } : {}),
              ...(finalEntities.length ? { caption_entities: finalEntities } : {})
            },
            rows_to_mark: rowIds
          }
        });
        continue;
      }

      if (type === 'video' && file_id) {
        out.push({
          json: {
            target_chat_id,
            refcode,
            community_name,
            group_key: `${groupKey}_${target_chat_id}`,
            source_group_key: groupKey,
            media_group_id: null,
            send_method: 'sendVideo',
            payload: {
              chat_id: target_chat_id,
              video: file_id,
              ...(finalContent ? { caption: finalContent } : {}),
              ...(finalEntities.length ? { caption_entities: finalEntities } : {})
            },
            rows_to_mark: rowIds
          }
        });
        continue;
      }

      if (type === 'document' && file_id) {
        out.push({
          json: {
            target_chat_id,
            refcode,
            community_name,
            group_key: `${groupKey}_${target_chat_id}`,
            source_group_key: groupKey,
            media_group_id: null,
            send_method: 'sendDocument',
            payload: {
              chat_id: target_chat_id,
              document: file_id,
              ...(finalContent ? { caption: finalContent } : {}),
              ...(finalEntities.length ? { caption_entities: finalEntities } : {})
            },
            rows_to_mark: rowIds
          }
        });
        continue;
      }

      // type=text và mọi type khác không phải media
      out.push({
        json: {
          target_chat_id,
          refcode,
          community_name,
          group_key: `${groupKey}_${target_chat_id}`,
          source_group_key: groupKey,
          media_group_id: null,
          send_method: 'sendMessage',
          payload: {
            chat_id: target_chat_id,
            text: finalContent || cta || 'Unsupported message type',
            ...(finalEntities.length ? { entities: finalEntities } : {})
          },
          rows_to_mark: rowIds
        }
      });

      continue;
    }

    // =========================
    // CASE 2: ALBUM
    // =========================
    const allowedAlbumTypes = ['photo', 'video'];

    const media = arr
      .filter(r => r.file_id && allowedAlbumTypes.includes(String(r.type || '').trim()))
      .map((r, idx) => {
        const item = {
          type: String(r.type || '').trim(),
          media: r.file_id
        };

        // chỉ item đầu có caption + CTA
        if (idx === 0) {
          const { content: finalContent, entities: finalEntities } =
            getFinalContentAndEntities(r, refcode, cta);

          if (finalContent) {
            item.caption = finalContent;
            if (finalEntities.length) {
              item.caption_entities = finalEntities;
            }
          }
        }

        return item;
      });

    if (!media.length) continue;

    out.push({
      json: {
        target_chat_id,
        refcode,
        community_name,
        group_key: `${groupKey}_${target_chat_id}`,
        source_group_key: groupKey,
        media_group_id: arr[0].media_group_id || null,
        send_method: 'sendMediaGroup',
        payload: {
          chat_id: target_chat_id,
          media
        },
        rows_to_mark: rowIds
      }
    });
  }
}

return out;

